code.C:
#include <stdio.h>
int main() {
    int T = 1;
    for (int tc = 0; tc < T; ++tc) {
        int sum = 0;
        for (int i = 1; i <= 10; ++i) sum += i;
        printf("%d\n", sum);
    }
    return 0;
}

